---@return LxVersion
function LxResUtil.ConvertToVersion(versionStr)
    local version = require("LApp.resource.LxVersion"):New()
    version:InitWithString(versionStr)
    return version
end

function LxResUtil.SetRepairMode(bRepair)
    PJXGameMgr:SetGameEnvVar("RepairMode", bRepair and "true" or "false")
end

function LxResUtil.IsInRepairMode()
    local isRepair = checkbool(PJXGameMgr:GetGameEnvVar("RepairMode"))
    return isRepair
end

function LxResUtil.UnloadAsset(asset)
    if not IsNull(asset) then
        Resources.UnloadAsset(asset)
    end
end

function LxResUtil.NewObject(prefab)
    local obj = NewObject(prefab)
    obj.name = prefab.name
    return obj
end

function LxResUtil.NewGameObject(name)
    return NewGameObject(name)
end

function LxResUtil.DestroyObject(obj)
    DestroyObject(obj)
end

function LxResUtil.DestroyChild(trans)
    if not trans then return end

    local num = trans.childCount
    if num > 0 then
        local child = nil
        for i = num,1,-1 do
            child = trans:GetChild(i-1)
            LxResUtil.DestroyObject(child.gameObject)
        end
    end
    trans = nil
end

function LxResUtil.DestroyImmediate(trans)
    if CS.IsValidObject(trans) then
        CS.DestroyImmediate(trans)
    end
    trans = nil
end
function LxResUtil.DestroyChildImmediate(trans)
    if not CS.IsValidObject(trans) then return end

    local num = trans.childCount
    if num > 0 then
        local child = nil
        for i = num,1,-1 do
            local child = trans:GetChild(i-1)
            LxResUtil.DestroyImmediate(child)
        end
    end
    trans = nil
end

